int main(void)
{
    int i;

    /* Clebsch-Gordan */
    for(i=0;i<(int)(sizeof(g_cg)/sizeof(g_cg[0]));i++){
        const cg_t *c=&g_cg[i];
        double got=clebsch_gordan(c->tj1,c->tm1,c->tj2,c->tm2,c->tJ,c->tM);
        TEST_NEAR(got,c->val,1e-12);
    }

    /* Racah W */
    for(i=0;i<(int)(sizeof(g_racah)/sizeof(g_racah[0]));i++){
        const racah_t *c=&g_racah[i];
        double got=racah_w(c->tj1,c->tj2,c->tJ,c->tj3,c->tj12,c->tj23);
        TEST_NEAR(got,c->val,1e-12);
    }

    /* Gaunt */
    for(i=0;i<(int)(sizeof(g_gaunt)/sizeof(g_gaunt[0]));i++){
        const gaunt_t *c=&g_gaunt[i];
        double got=gaunt(c->tl1,c->tm1,c->tl2,c->tm2,c->tl3,c->tm3);
        TEST_NEAR(got,c->val,1e-12);
    }

    SUMMARY();
}
